import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"击云（仿）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/击云（仿）.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/击云（仿）.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/击云（仿）.md"};function _(l,a,p,b,i,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"击云-仿",tabindex:"-1"},[s("击云（仿） "),e("a",{class:"header-anchor",href:"#击云-仿","aria-label":'Permalink to "击云（仿）"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调015")])])],-1),o('<h1 id="击云-仿-1" tabindex="-1">击云（仿） <a class="header-anchor" href="#击云-仿-1" aria-label="Permalink to &quot;击云（仿）&quot;">​</a></h1><p>击云（仿）<br> D+1000<br> 科技本质<br> 【我造的这把枪，锐利地可以击穿龙鳞。】———制作击云的工匠这么没说到。<br> 可惜，这不是那把击云枪，那位工匠也无法再锻造兵刃。<br> 用着精铁打造的这柄凡兵，只有其形，并无其意。它很朴实，但可靠。</p><p>武器类别：长枪<br> 专业：枪<br> 武器伤害：6L<br> 体积：3<br> 特性：长柄 双手 格挡2<br> 【虚数口袋】：枪柄上有着一块特殊工艺制作的宝石，能够连接一片及其狭小且特殊的虚数空间（3立方米）。这片空间经能够存储存储武器（包括击云本身）<br> 击云（仿）自带3/3能量池，每3小时回复1点，此能量无法被取出用作其他地方。从空间中取出不花费能量，收回花费1点（无论这次收回多少武器），取出武器需要使用一个迅捷动作。</p><p>【淬历】：长久的使用使得这把枪更加的顺手，内部的结构更加的坚固与锋锐。<br> 每经历一场影片，获得5点破甲（最多成长2次）<br> 【注能】：消耗2点通用任意能量，下次攻击额外获得2DP器械加值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
